def min_distance_origin_to_parabola_symmetric_y(A, C):
    """
    Calculates the minimum distance from the origin to the parabola y = Ax^2 + C.
    """
    # Distance squared D^2 = x^2 + (Ax^2 + C)^2
    # Let u = x^2. D^2 = A^2 u^2 + (1 + 2AC) u + C^2
    # This is a quadratic in u. We want to minimize it for u >= 0.

    if A == 0:
        return abs(C)

    a_q = A * A
    b_q = 1 + 2 * A * C
    c_q = C * C

    # Find vertex of the quadratic in u
    u_vertex = quadratic_vertex_x(a_q, b_q)

    if u_vertex > 0:
        min_d2 = a_q * u_vertex**2 + b_q * u_vertex + c_q
    else:
        min_d2 = c_q

    return math.sqrt(min_d2)

